+            )));
+        }
+        if first_color.is_none() {
+            first_color = Some(format!("#{trimmed}"));
+        }
+    }
+
+    if let Some(accent) = first_color {
+        theme.colors.accent = accent;
+    }
+
+    Ok(theme)
